CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE TABLE IF NOT EXISTS packages (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), ecosystem TEXT NOT NULL, registry_url TEXT NOT NULL, raw_name TEXT NOT NULL, normalized_name TEXT NOT NULL, namespace TEXT NOT NULL DEFAULT '', created_at TIMESTAMPTZ NOT NULL DEFAULT now(), UNIQUE(ecosystem, registry_url, normalized_name));
CREATE TABLE IF NOT EXISTS package_versions (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), package_id UUID NOT NULL REFERENCES packages(id), raw_version TEXT NOT NULL, normalized_version TEXT NOT NULL, normalization_status TEXT NOT NULL DEFAULT 'normalized', created_at TIMESTAMPTZ NOT NULL DEFAULT now(), UNIQUE(package_id, normalized_version));
CREATE TABLE IF NOT EXISTS artifacts (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), version_id UUID NOT NULL REFERENCES package_versions(id), artifact_type TEXT NOT NULL, filename TEXT NOT NULL, download_url TEXT NOT NULL, sha256 TEXT, observed_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE UNIQUE INDEX IF NOT EXISTS artifacts_predownload_key ON artifacts(version_id, artifact_type, filename, download_url) WHERE sha256 IS NULL;
CREATE UNIQUE INDEX IF NOT EXISTS artifacts_immutable_key ON artifacts(version_id, artifact_type, filename, sha256) WHERE sha256 IS NOT NULL;
CREATE TABLE IF NOT EXISTS artifact_observations (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), artifact_id UUID NOT NULL REFERENCES artifacts(id), source TEXT NOT NULL, observed_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS findings (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), stable_id TEXT NOT NULL UNIQUE, artifact_id UUID REFERENCES artifacts(id), severity TEXT NOT NULL, confidence TEXT NOT NULL, title TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS evidence_refs (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), finding_id UUID REFERENCES findings(id), artifact_id TEXT NOT NULL, path TEXT NOT NULL, start_line INT, end_line INT, start_byte BIGINT, end_byte BIGINT, hash TEXT, excerpt_redacted BOOLEAN NOT NULL DEFAULT true);
CREATE TABLE IF NOT EXISTS users (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), external_subject TEXT NOT NULL UNIQUE, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS events_outbox (id TEXT PRIMARY KEY, subject TEXT NOT NULL, payload JSONB NOT NULL, status TEXT NOT NULL DEFAULT 'pending', retry_count INT NOT NULL DEFAULT 0, next_attempt_at TIMESTAMPTZ NOT NULL DEFAULT now(), published_at TIMESTAMPTZ);
CREATE TABLE IF NOT EXISTS events_inbox (id TEXT PRIMARY KEY, subject TEXT NOT NULL, consumed_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS scheduled_jobs (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), kind TEXT NOT NULL, target TEXT NOT NULL, cadence_seconds INT NOT NULL CHECK (cadence_seconds >= 60), next_run_at TIMESTAMPTZ NOT NULL, lease_owner TEXT, lease_until TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), UNIQUE(kind,target));
